def evaluate_application(application):
    cs = application['credit_score']
    amount = application['loan_amount']
    dti = application['debt_to_income']
    purpose = application['loan_purpose']
    existing = application['is_existing_customer']

    if dti > 0.50:
        return {
            'approved': False,
            'reason_code': 'DTI_EXCEEDS_MAXIMUM',
            'decision_text': f'Debt-to-income ratio of {dti:.0%} exceeds the 50% maximum allowed.'
        }
    if cs >= 680 and dti <= 0.40:
        return {
            'approved': True,
            'reason_code': 'STANDARD_APPROVAL',
            'decision_text': f'Approved under standard underwriting: FICO {cs}, DTI {dti:.0%}.'
        }
    if cs >= 640 and purpose in ['home_improvement', 'medical'] and amount <= 15000:
        return {
            'approved': True,
            'reason_code': 'PURPOSE_EXCEPTION',
            'decision_text': f'Approved via purpose exception for {purpose} loan of ${amount:,.0f}.'
        }
    if existing and cs >= 620 and amount <= 8000:
        return {
            'approved': True,
            'reason_code': 'EXISTING_CUSTOMER_EXCEPTION',
            'decision_text': f'Approved via existing customer exception: FICO {cs}, loan ${amount:,.0f}.'
        }
    return {
        'approved': False,
        'reason_code': 'DOES_NOT_MEET_CRITERIA',
        'decision_text': f'Application denied: FICO {cs} and profile do not meet any approval pathway.'
    }
